// Formate le numéro WhatsApp pour l'affichage : "242065132012" -> "+242 06 513 20 12"
function formatWhatsApp(num: string): string {
  const d = (num || "").replace(/\D/g, "");
  if (d.startsWith("242") && d.length === 12) {
    const r = d.slice(3); // 065132012
    return `+242 ${r.slice(0,2)} ${r.slice(2,5)} ${r.slice(5,7)} ${r.slice(7,9)}`;
  }
  return num ? `+${d}` : "";
}

// Déduplique une liste de matchs par couple (paire non ordonnée), en gardant le plus récent (created_at).
function dedupeMatchesByCouple<T extends { user1?: string; user2?: string; created_at: string }>(list: T[]): T[] {
  const seen = new Set<string>();
  return [...list]
    .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
    .filter(m => {
      const key = [m.user1 || "", m.user2 || ""].sort().join("|");
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
}

