            const parseStat = (s: string) => { const digits = (String(s).match(/\d/g) || []).join(""); const target = parseInt(digits || "0", 10) || 0; const m = String(s).match(/[^\d\s][^\d]*$/); return { target, suffix: m ? m[0].trim() : "" }; };
